window.EXPERIENCE_DATA={corners:[{st:0,ed:.01,x:.515,y:.883,h:"l",v:"m",ch:"启程 · 广东工业大学",company:"广东工业大学",de:"广州",more:"2012 年，我从广东工业大学材料与能源学院毕业，获工学学士学位。四年理工科训练塑造了我的系统思维能力，也为后来转向用户体验设计埋下了种子——用工程思维理解技术，用设计思维触达人心。",imgs:[{src:"https://img.xiliab.online/uploads/my_biye.jpg",author:"LLXiao",desc:"广东工业大学工学学士毕业证书"},{src:"https://img.xiliab.online/uploads/my_xuewei.jpg",author:"LLXiao",desc:"广东工业大学工学学士学位证书"}]},{st:.01,ed:.15,x:.582,y:.688,h:"r",v:"m",ch:"机械设计师",company:"子律节能技术有限公司",de:"广州",more:"以实地测绘数据为基础，在 UG 中完成三维建模与工程出图，跟进生产全流程以确保制造精度，并通过数据驱动的迭代持续优化设计方案。这段工程实践让我深入理解了产品从概念到落地的完整链路，也积累了宝贵的跨领域协作经验。",stats:[{val:"10",unit:"+",label:"结构设计",icon:"<img src='assets/结构设计.webp' alt='结构设计' loading='lazy' decoding='async' />"},{val:"2",unit:"项",label:"项目落地",icon:"<img src='assets/项目落地.webp' alt='项目落地' loading='lazy' decoding='async' />"},{val:"持续",unit:"",label:"产品优化",icon:"<img src='assets/产品优化.webp' alt='产品优化' loading='lazy' decoding='async' />"}]},{st:.15,ed:.22,x:.724,y:.551,h:"c",v:"t",ch:"UI设计师",company:"朗岸文化公司",de:"广州",more:"负责产品界面视觉设计、组件规范制定与多端适配，与产品和开发团队协作推动设计方案高效落地。这一阶段我系统性地建立了自己的设计方法论——从视觉执行走向体验思维。",stats:[{val:"1000",unit:"+",label:"页面设计",icon:"<img src='assets/页面设计.webp' alt='页面设计' loading='lazy' decoding='async' />"},{val:"2",unit:"+",label:"组件规范",icon:"<img src='assets/组件规范.webp' alt='组件规范' loading='lazy' decoding='async' />"},{val:"高",unit:"",label:"交付效率",icon:"<img src='assets/交付效率.webp' alt='交付效率' loading='lazy' decoding='async' />"}]},{st:.22,ed:.3,x:.88,y:.442,h:"l",v:"m",ch:"高级UI设计师",company:"兆晶科技公司",de:"广州",more:"主导兆晶科技全线产品的用户体验设计与视觉方案，完成从产品流程规划到高保真输出的全流程设计。其中新风机手机端控制界面，将复杂设备操作转化为直观交互，显著提升了产品易用性与用户满意度。同时深度参与了品牌视觉体系的构建，包括品牌标志设计与 VI 规范制定。",stats:[{val:"3",unit:"+",label:"核心项目",icon:"<img src='assets/核心项目.webp' alt='核心项目' loading='lazy' decoding='async' />"},{val:"2",unit:"+",label:"设计体系",icon:"<img src='assets/设计体系.webp' alt='设计体系' loading='lazy' decoding='async' />"},{val:"推动",unit:"",label:"软硬件互通",icon:"<img src='assets/软硬件互通.webp' alt='软硬件互通' loading='lazy' decoding='async' />"}]},{st:.3,ed:.365,x:.892,y:.314,h:"r",v:"m",ch:"C端体验",company:"移动端与智能硬件体验",de:"广州",more:"面向消费者真实生活场景的体验设计，强调低学习成本、即时反馈与自然操作路径。通过移动端控制、家庭共享与状态可视化，让复杂设备能力转化为用户能直接感知的日常价值。",projects:[{title:"智能家居 · 新风系统",subtitle:"面向家庭空气管理场景，将新风设备参数与控制流程转化为清晰、低学习成本的移动端体验。",company:"兆晶科技公司",meta:["C端","智能硬件","微信小程序"],thumb:"https://img.xiliab.online/uploads/xinfeng_scene_01.jpg",article:'\n<strong>[项目挑战]</strong> 新风设备涉及 PM2.5、CO₂、风量、模式等多类信息，传统控制方式偏设备逻辑，用户需要先理解参数，才能判断当前空气状态与下一步操作。<br/><br/>\n<strong>[设计目标]</strong> 将硬件能力转化为面向家庭生活的空气管理体验，让用户能快速看懂状态、完成控制，并在多人共同使用时保持操作路径清晰。<br/><br/>\n<div class="case-summary" aria-label="新风系统设计策略">\n  <div><strong>状态可视化</strong><span>先呈现空气质量、设备运行状态和关键指标，帮助用户快速判断当前环境。</span></div>\n  <div><strong>高频控制</strong><span>将开关、风量、模式等核心动作前置，减少用户在参数中的查找成本。</span></div>\n  <div><strong>家庭共享</strong><span>覆盖成员授权、查看与协同控制，让设备管理符合真实家庭场景。</span></div>\n</div>\n<div class="case-flow" aria-label="新风系统体验流程">\n  <span>空气状态</span><i></i><span>指标判断</span><i></i><span>快捷控制</span><i></i><span>家庭协同</span>\n</div>\n<strong>[关键行动]</strong><br/>\n• <strong>状态可视化：</strong>围绕空气质量、设备运行状态和关键指标重组信息层级，帮助用户先判断环境，再决定操作。<br/>\n• <strong>高频路径重组：</strong>将开关、风量、模式等核心动作前置，减少用户在复杂参数中的查找成本。<br/>\n• <strong>家庭共享机制：</strong>支持成员共同管理设备，覆盖家庭场景下的授权、查看与协同控制需求。<br/><br/>\n<div class="case-callout"><strong>设计转译：</strong>用户真正想完成的不是“操作一台设备”，而是持续获得可理解、可调节、可共享的家庭空气管理体验。</div><br/>\n<strong>[成果与价值]</strong> 该方案形成了从“看懂空气状态”到“完成设备调节”的连续路径，让新风控制从设备操作转向日常空气管理。\n',media:[{src:"https://img.xiliab.online/uploads/xinfeng_scene_01.jpg",author:"LLXiao",desc:"<strong>极简空气管理体验</strong><br/><span style='opacity:0.7;'>整个流程步数少、路径清晰、操作便捷，精准契合用户“想呼吸好空气，而非控制设备”的真实动机，体现出高效直观的智能产品体验设计理念。</span>"},{src:"https://img.xiliab.online/uploads/xinfeng_scene_02.jpg",author:"LLXiao",desc:"<strong>智能设备协同体验</strong><br/><span style='opacity:0.7;'>整体流程易理解、误操作风险低，强化了“控制权可授权、设备共管理”的家庭场景价值，体现出产品对多用户协同体验的深度考虑与贴心设计。</span>"},{src:"https://img.xiliab.online/uploads/xinfeng_scene_other.jpg",author:"LLXiao",desc:"<strong>场景全覆盖</strong><br/><span style='opacity:0.7;'>通过将功能模块轻量化、流程化，使用户可在不同场景下高效完成任务。</span>"}]}]},{st:.365,ed:.4,x:.79,y:.24,h:"r",v:"m",ch:"设计经理",company:"金蓝盟公司",de:"广州",more:"主导产品前期的战略定位与需求分析，输出高质量的交互方案与界面视觉；同时负责设计团队管理与新人培养，把控设计产出质量与项目进度。从执行者到管理者，我开始用更宏观的视角理解产品价值与设计策略的关系。",stats:[{val:"10",unit:"+",label:"部门协作",icon:"<img src='assets/部门协作.webp' alt='部门协作' loading='lazy' decoding='async' />"},{val:"0",unit:"延时",label:"设计交付",icon:"<img src='assets/设计交付.webp' alt='设计交付' loading='lazy' decoding='async' />"},{val:"完善",unit:"",label:"团队培养",icon:"<img src='assets/团队培养.webp' alt='团队培养' loading='lazy' decoding='async' />"}]},{st:.435,ed:.51,x:.8,y:.05,h:"c",v:"b",ch:"业务线设计负责人",company:"三维家公司",de:"广州",more:"带领约十人的 UED 团队，负责公司平台产品部的全盘设计工作。通过优化团队工作流与设计规范，系统性提升设计效率与输出质量；与业务部门深度协作，打通产品设计流程中的关键瓶颈，推动用户体验成为产品决策的核心要素之一。",stats:[{val:"3",unit:"+",label:"流程优化",icon:"<img src='assets/流程优化.webp' alt='流程优化' loading='lazy' decoding='async' />"},{val:"7",unit:"+",label:"产品迭代",icon:"<img src='assets/产品迭代.webp' alt='产品迭代' loading='lazy' decoding='async' />"},{val:"跟进",unit:"",label:"质量把控",icon:"<img src='assets/质量把控.webp' alt='质量把控' loading='lazy' decoding='async' />"}]},{st:.51,ed:.62,x:.47,y:.178,h:"c",v:"t",ch:"B端产品",company:"企业级复杂系统体验",de:"广州",more:"面向企业组织、专业设计师、销售与客服团队的复杂系统体验设计，重点处理多角色协作、流程效率、信息架构、数据决策与业务增长之间的关系。",projects:[{title:"企业学习 · 商学院",subtitle:"面向企业学习平台，系统识别体验问题并沉淀量化迭代依据，支持课程与学习流程优化。",company:"金蓝盟公司",meta:["B端","企业学习","平台体验"],thumb:"https://img.xiliab.online/uploads/JLM_sxy_06.jpg",article:'\n<strong>[项目挑战]</strong> 商学院平台同时承载课程学习、内训服务与咨询内容，信息类型多、用户任务分散，学习路径和后台管理都需要更清晰的组织方式。<br/><br/>\n<strong>[设计目标]</strong> 通过系统化体验审查，识别影响学习效率、内容查找与操作理解的问题，并为后续产品迭代建立可执行的问题清单。<br/><br/>\n<div class="case-metrics" aria-label="商学院体验审查数据">\n  <div><strong>38</strong><span>故障点</span></div>\n  <div><strong>21</strong><span>产品优化机会</span></div>\n  <div><strong>260</strong><span>交互问题</span></div>\n  <div><strong>182</strong><span>视觉改进项</span></div>\n</div>\n<strong>[关键行动]</strong><br/>\n• <strong>体验问题盘点：</strong>围绕可用性、交互反馈、视觉一致性和流程完整性进行审查，拆分问题类型与优先级。<br/>\n• <strong>信息分类优化：</strong>按岗位、难度和学习目标梳理课程组织方式，提升内容查找与路径理解效率。<br/>\n• <strong>学习界面聚焦：</strong>通过减少干扰、强化核心内容区和优化筛选控件，让学习过程更容易进入和持续。<br/><br/>\n<div class="case-summary" aria-label="商学院审查框架">\n  <div><strong>可用性审查</strong><span>识别故障、误操作、反馈不足等影响学习效率的问题。</span></div>\n  <div><strong>信息分类</strong><span>按岗位、难度和学习目标重组课程查找路径。</span></div>\n  <div><strong>学习聚焦</strong><span>减少界面干扰，让用户更容易进入和持续学习。</span></div>\n</div>\n<strong>[成果与价值]</strong> 项目共梳理 38 个故障点、21 项产品优化机会、260 个交互问题及 182 个视觉改进项，为后续迭代提供了明确的量化依据。\n',media:[{src:"https://img.xiliab.online/uploads/JLM_sxy_06.jpg",author:"LLXiao",desc:"<strong>洞察体验问题</strong><br/><span style='opacity:0.7;'>识别出38个故障点、21项产品优化、260个交互问题与182个视觉改进项，结合可用性原则（如防错、易取、一致性等）进行了系统梳理，为后续设计优化提供了明确的落脚点与量化依据。</span>"},{src:"https://img.xiliab.online/uploads/JLM_sxy_09.jpg",author:"LLXiao",desc:"<strong>提升信息可达性与操作效率</strong><br/><span style='opacity:0.7;'>课程模块按岗位与难度分类，帮助用户精准匹配所需内容；左侧导航布局明确，增强层级感与页面掌控力；下拉答题筛选则通过位置与样式改进，提升信息查找效率与响应速度。整体设计在内容组织、导航引导和操作便捷性上实现精细化提升。</span>"},{src:"https://img.xiliab.online/uploads/JLM_sxy_10.jpg",author:"LLXiao",desc:"<strong>打造沉浸式学习体验</strong><br/><span style='opacity:0.7;'>界面元素简化后，整体更聚焦于核心内容，减少视觉干扰；支持区域最小化与视图切换，增强用户自主控制感。整体设计更贴近真实学习场景，极大改善了使用流畅性与学习专注度。</span>"},{src:"https://img.xiliab.online/uploads/JLM_sxy_11.jpg",author:"LLXiao",desc:"<strong>认知统一化设计</strong><br/><span style='opacity:0.7;'>有效降低了用户学习成本和操作误差，同时提升了设计的复用效率和系统可扩展性，为复杂业务流程提供了可控、易用的设计基础。</span>"},{src:"https://img.xiliab.online/uploads/JLM_sxy_12.jpg",author:"LLXiao",desc:"<strong>高参与感学习体验</strong><br/><span style='opacity:0.7;'>整体设计不仅提升了学习平台的专业感，也增强了互动性与用户黏性，体现出精细化的用户运营思维与智能化产品能力。</span>"}]},{title:"家装设计 · 三维家",subtitle:"面向家装设计工具，梳理从方案创建到展示交付的任务路径，支持专业设计流程连续推进。",company:"三维家公司",meta:["B端","设计工具","3D可视化"],thumb:"https://img.xiliab.online/uploads/3VJ_web.jpg",article:'\n<strong>[项目挑战]</strong> 家装设计平台需要同时承载 3D 设计、户型建模、方案库、素材模型和施工图等复杂能力，用户在开始设计、查找资源与展示方案之间容易产生路径断点。<br/><br/>\n<strong>[设计目标]</strong> 梳理专业设计工具的信息架构与任务路径，让用户能够围绕方案创建、编辑、浏览和交付展示形成连续操作。<br/><br/>\n<div class="case-flow" aria-label="家装设计工具链路">\n  <span>方案入口</span><i></i><span>3D设计</span><i></i><span>全景浏览</span><i></i><span>展示交付</span>\n</div>\n<strong>[关键行动]</strong><br/>\n• <strong>任务入口梳理：</strong>围绕新建方案、上传方案、模型资源与课程学习等场景重组入口优先级。<br/>\n• <strong>设计链路组织：</strong>将方案创建、3D 浏览和交付展示串联成更完整的流程，减少跨模块理解成本。<br/>\n• <strong>专业信息分层：</strong>在工具能力密集的界面中区分核心任务、辅助资源与服务内容，支持用户按目标推进。<br/><br/>\n<div class="case-summary" aria-label="家装设计平台设计策略">\n  <div><strong>任务入口</strong><span>让新建、上传、资源查找等高频起点更容易被发现。</span></div>\n  <div><strong>设计链路</strong><span>把方案创建、编辑、浏览和交付组织成连续路径。</span></div>\n  <div><strong>信息分层</strong><span>在复杂工具能力中区分核心任务、辅助资源和服务内容。</span></div>\n</div>\n<strong>[成果与价值]</strong> 该设计支持从灵感获取、方案设计到展示交付的连续体验，帮助平台以更清晰的信息路径承载专业设计流程。\n',media:[{src:"https://img.xiliab.online/uploads/3VJ_web.jpg",author:"LLXiao",desc:"<strong>专业可信、技术驱动</strong><br/><span style='opacity:0.7;'>从“产品能力”到“服务对象”，逐步构建完整的信息路径，极大降低了设计门槛，优化了从方案设计到交付的整个决策流程。</span>"}]},{title:"全渠道私域 · 微聊",subtitle:"面向全渠道客服与私域运营场景，梳理获客到成交的协作链路，支持多角色高效沟通。",company:"银光科技公司",meta:["B端","CRM","客服系统"],thumb:"https://img.xiliab.online/uploads/YG_wl_16.jpg",article:'\n<strong>[项目挑战]</strong> 企业客户沟通分散在多个渠道，客服、销售与后台管理角色需要在获客、接待、跟进和成交之间协作，信息切换与任务衔接容易影响服务连续性。<br/><br/>\n<strong>[设计目标]</strong> 梳理全渠道客户沟通流程，将客户信息、沟通记录、运营动作和数据反馈组织为可协作的服务路径。<br/><br/>\n<div class="case-flow" aria-label="全渠道私域运营流程">\n  <span>获客</span><i></i><span>接待</span><i></i><span>跟进</span><i></i><span>成交</span>\n</div>\n<div class="case-role-grid" aria-label="全渠道私域角色协作">\n  <div><strong>后台</strong><span>配置渠道、客户资料、标签和运营动作，保证团队使用同一套客户规则。</span></div>\n  <div><strong>销售</strong><span>在客户上下文中查看资料、沟通记录和待跟进动作，减少来回切换。</span></div>\n  <div><strong>客户</strong><span>从不同渠道进入服务链路，获得更连续的咨询、跟进和成交体验。</span></div>\n</div>\n<strong>[关键行动]</strong><br/>\n• <strong>全流程梳理：</strong>拆解从获客、沟通到成交的关键阶段，明确不同角色在每一阶段的任务与信息需求。<br/>\n• <strong>信息架构重构：</strong>围绕客户资料、标签画像、会话记录和营销触达建立统一查看与操作路径。<br/>\n• <strong>沟通动作布局：</strong>将智能回复、数据分析和客服绩效信息放入业务流程中，支持团队持续跟进。<br/><br/>\n<div class="case-callout"><strong>协作重点：</strong>把客户资料、会话记录和运营动作放回同一客户上下文，减少跨渠道沟通造成的信息断点。</div><br/>\n<strong>[成果与价值]</strong> 方案形成了覆盖多渠道接入、客户识别与运营跟进的协作体验，支持客服与销售在同一客户上下文中推进服务。',media:[{src:"https://img.xiliab.online/uploads/YG_wl_16.jpg",author:"LLXiao",desc:"<strong>以用户为中心的客户营销全流程体验设计</strong><br/><span style='opacity:0.7;'>从获客、沟通到成交的完整路径，具体分析了每一阶段的关键任务、用户行为及不同角色（后台、销售、客户）的互动模式。同时，针对每阶段的用户痛点，明确提出了有针对性的产品优化机会。</span>"},{src:"https://img.xiliab.online/uploads/YG_wl_18.jpg",author:"LLXiao",desc:"<strong>设计目标与策略定义</strong><br/><span style='opacity:0.7;'>围绕客户沟通连续性与团队协作效率，制定了三类设计策略：重构信息架构提升内容发现性，优化页面布局简化操作流程，并将智能回复与数据能力放入关键沟通节点。</span>"},{src:"https://img.xiliab.online/uploads/YG_wl_22.jpg",author:"LLXiao",desc:"<strong>设计验证成果</strong><br/><span style='opacity:0.7;'>产品设计在实际业务环境中的成功落地，有效验证了设计目标的实现。</span>"}]},{title:"SCRM · 金桥",subtitle:"面向私域电商销售场景，整合多平台客户数据与企微侧边栏信息，支持跟进决策。",company:"银光科技公司",meta:["B端","SCRM","私域电商"],thumb:"https://img.xiliab.online/uploads/YG_jq_home.jpg",article:'\n<strong>[项目挑战]</strong> 私域电商客户信息分布在微信、抖音等多个平台，销售跟进时需要同时理解客户来源、标签、订单与库存相关信息，缺少连续上下文会影响判断效率。<br/><br/>\n<strong>[设计目标]</strong> 整合多平台客户数据，并在企业微信侧边栏中提供可快速理解的客户资料与跟进线索，支持销售形成下一步行动判断。<br/><br/>\n<div class="case-role-grid" aria-label="SCRM数据聚合">\n  <div><strong>多平台客户</strong><span>聚合微信、抖音等来源渠道，让销售先识别客户从哪里来。</span></div>\n  <div><strong>业务数据</strong><span>关联订单、云仓和营销规则，把运营动作连接到客户状态。</span></div>\n  <div><strong>客户标签</strong><span>沉淀标签、跟进状态和基础资料，支持下一步判断。</span></div>\n</div>\n<div class="case-flow" aria-label="SCRM跟进决策链路">\n  <span>多平台数据</span><i></i><span>客户画像</span><i></i><span>跟进判断</span><i></i><span>运营动作</span>\n</div>\n<strong>[关键行动]</strong><br/>\n• <strong>客户资料聚合：</strong>将来源渠道、客户标签、跟进状态和基础资料组织在同一信息框架内。<br/>\n• <strong>业务数据联动：</strong>围绕订单、云仓与营销规则建立关联路径，让运营动作能连接到具体客户状态。<br/>\n• <strong>关键信息突出：</strong>在高密度信息中优先呈现影响跟进判断的内容，减少销售查找和切换成本。<br/><br/>\n<div class="case-callout"><strong>信息组织重点：</strong>不是堆叠更多客户字段，而是让销售在高密度信息中优先看到影响跟进判断的内容。</div><br/>\n<strong>[成果与价值]</strong> 该方案形成了从客户识别、资料查看到运营跟进的系统支撑；所属企业微信营销平台已覆盖超百家企业客户，该表述用于说明平台服务范围，不作为单项目增长结果。',media:[{src:"https://img.xiliab.online/uploads/YG_jq_home.jpg",author:"LLXiao",desc:"<strong>整合客户资料与销售跟进信息</strong><br/><span style='opacity:0.7;'>围绕客户画像、线索管理与销售分析建立统一的信息框架，让销售在同一视图中理解客户来源、状态与可执行动作，支持私域运营团队进行持续跟进。</span>"}]}]},{st:.62,ed:.72,x:.18,y:.305,h:"l",v:"t",ch:"设计负责人",company:"银光科技公司",de:"广州",more:"主导银光科技全线产品的用户体验设计，覆盖客户端、手机端与管理后台三大用户端。建立跨平台组件规范体系，提升产品一致性与设计交付效率。其中企业微信赋能营销平台已助力超百家企业客户实现业务增长，获得市场广泛认可。",stats:[{val:"1",unit:"+",label:"设计体系",icon:"<img src='assets/设计体系.webp' alt='设计体系' loading='lazy' decoding='async' />"},{val:"3",unit:"+",label:"业务增长",icon:"<img src='assets/业务增长.webp' alt='业务增长' loading='lazy' decoding='async' />"},{val:"可落地",unit:"",label:"产品策略",icon:"<img src='assets/产品策略.webp' alt='产品策略' loading='lazy' decoding='async' />"}]},{st:.72,ed:.88,x:.238,y:.635,h:"l",v:"m",ch:"AI / 自动化",company:"智能运营与流程自动化",de:"广州",more:"围绕重复运营任务、客户行为追踪与数据辅助决策的自动化体验设计。这里重点展示如何把繁琐流程拆解为可配置、可追踪、可复用的产品能力。",projects:[{title:"AI托管 · 智能客服接待",subtitle:"面向企业客服接待场景，将权限说明、AI 回复机制与人工接管组织为可控、可信的智能服务体验。",company:"银光科技公司",meta:["AI产品","智能客服","人机协同"],thumb:"https://img.xiliab.online/uploads/ai-tuoguan-access-overview.jpg",article:'\n<div class="case-summary" aria-label="AI托管核心能力">\n  <div><strong>权限可解释</strong><span>未授权时明确说明原因，让客服知道为什么不能使用以及下一步找谁处理。</span></div>\n  <div><strong>回复有依据</strong><span>围绕客户信息、意图识别、知识库和智能体组织 AI 回复链路。</span></div>\n  <div><strong>人工可接管</strong><span>托管中保留刷新聊天和人工接管，客服可随时回到人工服务。</span></div>\n</div>\n<strong>[项目背景]</strong> 企业客服在高频咨询场景中需要反复处理相似问题，同时还要查看客户资料、判断客户意图并保持服务连续性。AI 托管可以分担标准化回复，但如果权限原因、回复依据和人工控制点不清楚，客服会难以判断当前服务是否可信、是否可控。<br/><br/>\n<strong>[核心设计]</strong><br/>\n• <strong>权限入口清晰：</strong>无权限状态不只展示报错，而是说明“当前工号未开启 AI 托管授权”，同时呈现 AI 托管能力和入口，让用户理解功能边界与开通路径。<br/>\n• <strong>回复链路可理解：</strong>通过客户信息、用户画像、AI 识别、知识库和智能体，将 AI 回复从单点按钮转化为可解释的服务流程。<br/>\n• <strong>托管状态可中断：</strong>在托管中的客服工作台保留“刷新聊天”和“人工接管”，让客服可以继续观察会话，也能在复杂场景下及时切回人工。<br/><br/>\n<div class="case-flow" aria-label="AI托管服务流程">\n  <span>托管客户</span><i></i><span>客户信息</span><i></i><span>意图识别</span><i></i><span>知识库</span><i></i><span>AI回复</span><i></i><span>人工接管</span>\n</div>\n<strong>[人机协同设计]</strong> 该方案没有把 AI 做成脱离业务的独立功能页，而是放回客服工作台：左侧保留会话列表，中间承接客户沟通，右侧继续呈现客户资料与操作记录。AI 负责处理可复用问答，客服负责判断复杂意图和关键服务节点。<br/><br/>\n<strong>[权限与信任机制]</strong> 权限总览图先解释为什么不能使用，再展示自动响应、人工接管和使用价值；机制图说明 AI 回复并非凭空生成，而是由客户信息、意图识别和知识库共同支撑；工作台图则把“AI托管中”和“人工接管”放在同一操作区，降低自动回复的不确定感。<br/><br/>\n<div class="case-callout"><strong>可信 AI 设计重点：</strong>不是让 AI 替代客服，而是在客服工作台里提供可解释、可控制、可接管的自动化能力。</div><br/>\n<strong>[设计价值]</strong> 该案例体现的是把 AI 能力嵌入真实服务流程的产品设计能力：既让重复咨询可以被自动化处理，也保留权限治理、人工判断和服务连续性，让智能客服从“可用功能”变成“可被团队放心使用的工作机制”。',media:[{src:"https://img.xiliab.online/uploads/ai-tuoguan-access-overview.jpg",author:"LLXiao",desc:"<strong>AI托管权限与功能总览</strong><br/><span style='opacity:0.7;'>通过无权限提示、AI托管入口和功能说明，让客服先理解当前账号为什么不能使用，以及 AI 托管可以覆盖哪些接待场景。</span>"},{src:"https://img.xiliab.online/uploads/ai-tuoguan-reply-workflow.jpg",author:"LLXiao",desc:"<strong>AI回复机制链路</strong><br/><span style='opacity:0.7;'>将托管客户、用户画像、意图识别、知识库与智能体串联起来，说明 AI 回复不是单点动作，而是一条有上下文依据的服务链路。</span>"},{src:"https://img.xiliab.online/uploads/ai-tuoguan-active-workbench.jpg",author:"LLXiao",desc:"<strong>AI托管中的客服工作台</strong><br/><span style='opacity:0.7;'>在真实会话界面中呈现“AI托管中”状态，并保留刷新聊天与人工接管，让客服可以观察自动回复，也能随时切回人工处理。</span>"}]},{title:"内容运营 · 栏目系统",subtitle:"面向私域内容运营场景，通过自动邀约与行为追踪，推动视频完播率提升 21%、员工工作量降低 38%。",company:"银光科技公司",meta:["AI / 自动化","私域运营","数据追踪"],thumb:"https://img.xiliab.online/uploads/YG_lanmu_01.jpg",article:'\n<strong>[项目挑战]</strong> 私域内容运营高度依赖员工手动邀约、提醒和回访，客户观看视频后的行为数据难以及时回流，销售很难判断哪些客户值得优先跟进。<br/><br/>\n<strong>[设计目标]</strong> 将重复的邀约、观看追踪与跟进动作沉淀为可配置流程，让运营团队能够用统一规则完成客户触达，并把观看行为转化为可使用的跟进线索。<br/><br/>\n<div class="case-metrics" aria-label="栏目系统项目结果">\n  <div><strong>21%</strong><span>视频观看完整率提升</span></div>\n  <div><strong>38%</strong><span>员工工作量降低</span></div>\n</div>\n<div class="case-flow" aria-label="栏目系统自动化流程">\n  <span>客户来源</span><i></i><span>自动邀约</span><i></i><span>观看追踪</span><i></i><span>标签沉淀</span><i></i><span>销售跟进</span>\n</div>\n<strong>[关键行动]</strong><br/>\n• <strong>自动邀约配置：</strong>根据客户来源与运营阶段设置绑定链接、欢迎语和触达规则，减少重复手动操作。<br/>\n• <strong>行为追踪与标签：</strong>记录观看进度和互动行为，并将关键行为沉淀为客户标签，支持后续分层跟进。<br/>\n• <strong>企微侧边栏辅助：</strong>在销售沟通场景中呈现客户观看数据与标签信息，帮助销售理解客户当前状态。<br/><br/>\n<div class="case-callout"><strong>自动化价值：</strong>减少重复邀约和回访动作，同时把观看行为转化为可跟进线索，让销售更容易判断优先级。</div><br/>\n<strong>[成果与价值]</strong> 项目落地后，视频观看完整率提升 21%，员工工作量降低 38%。',media:[{src:"https://img.xiliab.online/uploads/YG_lanmu_01.jpg",author:"LLXiao",desc:"<strong>员工工作量降低38%，涉及用户超十万</strong><br/><span style='opacity:0.7;'>不少行业营销都依赖私域流量运营。随着短视频成为常见转化载体，中小企业仍大量使用人工方式完成邀约、提醒与回访，导致员工没有足够精力识别并跟进高价值客户。</span>"},{src:"https://img.xiliab.online/uploads/YG_lanmu_02.jpg",author:"LLXiao",desc:"<strong>目标一：提高观看视频客户数；目标二：提高视频观看完播率；目标三：沉淀可跟进线索</strong><br/><span style='opacity:0.7;'>企业在私域流量运营、内容分发与客户管理方面存在传统营销手段枯燥、数据割裂、重复工作量大等难题。通过对流程进行跟进分析，主要流失集中在视频观看阶段，原因包括提醒不足、内容体系不清晰以及观看动力不足。</span>"},{src:"https://img.xiliab.online/uploads/YG_lanmu_03.jpg",author:"LLXiao",desc:"<strong>统一设置，自动化流程，规范化工作，降低员工工作量和培训成本</strong><br/><span style='opacity:0.7;'>我将员工最繁琐重复的工作通过预设配置自动化，极大降低了员工的工作量。员工仅需点击发送即可完成会员的激活、邀约与回访。话术的统一减少了培训成本与出错率。</span>"},{src:"https://img.xiliab.online/uploads/YG_lanmu_04.jpg",author:"LLXiao",desc:"<strong>视频观看完整率提升21%，员工工作量降低38%</strong><br/><span style='opacity:0.7;'>通过自动化邀约、观看追踪与客户标签沉淀，团队减少了重复触达工作，并获得了更清晰的客户跟进依据。</span>"}]}]},{st:.88,ed:.94,x:.37,y:.76,h:"l",v:"m",ch:"人生在继续，体验永不停",company:"下一段旅程",de:"广州",more:"交互不止于屏幕，人生亦是界面。一念起，万相动。<br/>每个当下，都是一次设计；每段经历，都是一种体验。<br/>用设计的心去生活，用生活的感去做设计。",imgs:[{src:"https://img.xiliab.online/uploads/keep_going_myself.jpg",author:"LLXiao",desc:"<strong>继续前行</strong>"}]}]};